import { DurationChipAtom } from '../../../tooltip-atoms/components/DurationChipAtom/DurationChipAtom.js';

/**
 * @internal
 */
export interface DurationChipProps {
  duration: number;
}

/**
 * @internal
 */
export const DurationChip = ({ duration }: DurationChipProps) => {
  const durationInMs = duration * 1000;

  const from = new Date();
  const to = new Date(from.getTime() + durationInMs);

  return <DurationChipAtom from={from} to={to} />;
};

DurationChip['displayName'] = 'ChartTooltip.DurationChip';
